  inventory_id, material_id, quantity, lot_no,
  expiration_date, received_date, warehouse_code,
  status, inventory_status
) VALUES (
  #{inventoryId}, #{materialId}, #{quantity}, #{lotNo},
  #{expirationDate}, #{receivedDate}, #{warehouseCode},
  #{status}, #{inventoryStatus}
)

